var _SALT_G = 'vqr_s3cr3t_2025_nguyenvan';

function simpleHash(str) {
  var hash = 0x811c9dc5;
  for (var i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash * 0x01000193) >>> 0;
  }
  for (var j = 0; j < _SALT_G.length; j++) {
    hash ^= _SALT_G.charCodeAt(j);
    hash = ((hash << 5) | (hash >>> 27)) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}

function verifyToken(token) {
  try {
    var b64 = token.replace(/-/g, '+').replace(/_/g, '/');
    while (b64.length % 4) b64 += '=';
    var decoded = atob(b64);
    var parts = decoded.split('|');
    if (parts.length !== 3) { console.log('FAIL: parts != 3, got', parts.length); return false; }
    var user = parts[0], ts = parts[1], sig = parts[2];
    var age = Date.now() - parseInt(ts, 10);
    if (isNaN(age) || age > 86400000) { console.log('FAIL: expired, age=', age); return false; }
    var expected = simpleHash(user + ':' + ts + ':' + _SALT_G);
    console.log('sig=', sig, 'expected=', expected, 'match=', sig === expected);
    return sig === expected;
  } catch(e) {
    console.log('FAIL: exception', e);
    return false;
  }
}

function showPage() {
  var loader  = document.getElementById('appLoader');
  var content = document.getElementById('appContent');
  console.log('appLoader:', loader);
  console.log('appContent:', content);
  if (loader)  loader.style.display  = 'none';
  if (content) content.style.display = '';
  console.log('Page shown!');
}

function checkAuth() {
  var hash = window.location.hash;
  console.log('hash:', hash);

  if (!hash || hash.indexOf('#tk=') !== 0) {
    console.log('No token → redirect login');
    window.location.replace('login.html');
    return;
  }

  var token = hash.slice(4);
  console.log('token:', token.substring(0, 20) + '...');

  var ok = verifyToken(token);
  console.log('verify result:', ok);

  if (ok) {
    showPage();
  } else {
    console.log('Token invalid → redirect login');
    window.location.replace('login.html');
  }
}

function logout() {
  window.location.replace('login.html');
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', checkAuth);
} else {
  checkAuth();
}
